const data = $input.first().json;
const user = data.user;
const sub = data.subscription;

const planName = sub.plan_type === 'annual' ? 'Annuel' : 'Mensuel';
const periodEnd = sub.period_end ? new Date(sub.period_end).toLocaleDateString('fr-FR') : '';

const emailBody = `Bonjour ${user.name},

Merci pour votre abonnement à Tempo Budget !

Votre paiement de ${sub.amount.toFixed(2)} ${sub.currency} a bien été reçu.

Détails de votre abonnement :
- Plan : ${planName}
- Montant : ${sub.amount.toFixed(2)} ${sub.currency}
${periodEnd ? '- Prochaine échéance : ' + periodEnd : ''}

Vous pouvez accéder à votre tableau de bord dès maintenant :
https://tempo-finance.com/dashboard

Pour gérer votre abonnement (factures, moyen de paiement, résiliation) :
https://tempo-finance.com/settings

Cordialement,
L'équipe Tempo Budget`;

return {
  json: {
    to: user.email,
    subject: `Confirmation de paiement - Tempo Budget`,
    body: emailBody
  }
};
